import { useEffect, useLayoutEffect } from "react"

export const useSafeLayoutEffect =
  typeof globalThis?.document !== "undefined" ? useLayoutEffect : useEffect

let [expandedKeys, setExpandedKeys] = useControlledState(
  props.expandedKeys ? new Set(props.expandedKeys) : undefined,
  props.defaultExpandedKeys ? new Set(props.defaultExpandedKeys) : new Set(),
  props.onExpandedChange
);

let {
    CollectionRoot,
    isVirtualized,
    layoutDelegate,
    dropTargetDelegate: ctxDropTargetDelegate
  } = useContext(CollectionRendererContext);

let {
    isVirtualized,
    layoutDelegate,
    dropTargetDelegate: ctxDropTargetDelegate,
    CollectionRoot
  } = useContext(CollectionRendererContext);

let filteredCollection = useMemo(
  () => (filter ? collection.filter(filter) : collection),
  [collection, filter]
);

useUpdateEffect(() => {
    if (selectedDateDescription) {
      announce(selectedDateDescription, 'polite', 4000);
    }
    // handle an update to the caption that describes the currently selected range, to announce the new value
  }, [selectedDateDescription]);

const pureComponentPrototype = (PureComponent.prototype = new ComponentDummy());
pureComponentPrototype.constructor = PureComponent;
// Avoid an extra prototype jump for these methods.
assign(pureComponentPrototype, Component.prototype);
pureComponentPrototype.isPureReactComponent = true;

export {Component, PureComponent};

export interface LayoutGroupContextProps {
    id?: string
    group?: NodeGroup
    forceRender?: VoidFunction
}

export const LayoutGroupContext = createContext<LayoutGroupContextProps>({})

if (!areSetsEqual(lastExpandedKeys, expandedKeys) || collection !== lastCollection) {
  setFlattenedCollection(collection.withExpandedKeys(lastExpandedKeys, expandedKeys));
  setLastCollection(collection);
  setLastExpandedKeys(expandedKeys);
}

let {
    dragAndDropHooks,
    keyboardNavigationBehavior = 'arrow',
    layout = 'stack',
    orientation = 'vertical'
  } = props;

let {
    selectionMode = 'none',
    expandedKeys: propExpandedKeys,
    defaultExpandedKeys: propDefaultExpandedKeys,
    onExpandedChange,
    disabledBehavior = 'all'
  } = props;

let {
    inputRef,
    collectionRef,
    filter,
    disableAutoFocusFirst = false,
    disableVirtualFocus = false
  } = props;

let descriptionProps = useHighlightSelectionDescription({
  selectionManager: manager,
  hasItemActions: !!(onRowAction || onCellAction)
});

let descriptionProps = useHighlightSelectionDescription({
  selectionManager: state.selectionManager,
  hasItemActions: !!onAction
});

checkboxGroupData.set(state, {
  name,
  form,
  descriptionId: descriptionProps.id,
  errorMessageId: errorMessageProps.id,
  validationBehavior
});
